select 
from tutor_profile p left join sys_user u on u.user_id = p.user_id
where p.user_id = #{userId}

select 
from tutor_profile p left join sys_user u on u.user_id = p.user_id
where p.profile_id = #{profileId}

select 
from tutoring_request r left join sys_user u on u.user_id = r.publisher_id
where r.request_id = #{requestId}

mapper.update:
update tutoring_request
set status = #{target}, update_by = #{updateBy}, update_time = sysdate()
where request_id = #{requestId} and status = #{current}

update tutoring_request
set schedule_text = #{scheduleText}, update_by = #{updateBy}, update_time = sysdate()
where request_id = #{requestId}

update tutoring_match
set status = #{target}, update_by = #{updateBy}, update_time = sysdate()
where match_id = #{matchId} and status = #{current}

update tutoring_match
set status = '4', cancel_reason = #{cancelReason}, update_by = #{updateBy}, update_time = sysdate()
where match_id = #{matchId} and status = #{current}

update tutoring_match
set reschedule_text = #{rescheduleText}, update_by = #{updateBy}, update_time = sysdate()
where match_id = #{matchId}

mapper.select:
select from tutoring_payment p join tutoring_match m on m.match_id = p.match_id join tutoring_request r on r.request_id = m.request_id left join sys_user payer on payer.user_id = p.payer_id left join sys_user tutor on tutor.user_id = m.tutor_id where 1 = 1
and p.status = #{status}
order by p.status asc, p.create_time desc, p.payment_id desc

select f.followup_id, f.match_id, r.subject, publisher.nick_name publisher_name, tutor.nick_name tutor_name, f.content, f.next_action, f.status, f.create_by, f.create_time from tutoring_followup f join tutoring_match m on m.match_id = f.match_id join tutoring_request r on r.request_id = m.request_id left join sys_user publisher on publisher.user_id = r.publisher_id left join sys_user tutor on tutor.user_id = m.tutor_id where 1 = 1
and f.match_id = #{matchId}
and f.status = #{status}
order by f.create_time desc, f.followup_id desc

select notification_id notificationId, user_id userId, title, content, read_status readStatus, create_time createTime from tutoring_notification where user_id = #{userId}
and read_status = #{readStatus}
and title like concat('%', #{title}, '%')
order by create_time desc limit 100
